d"}, "fulfillment_status_name": {"name": "fulfillment_status_name", "type": "status", "width": 120, "header": "Status"}, "customer_contact_info_id": {"name": "customer_contact_info_id", "type": "lookup", "width": 200, "header": "Contact Info", "lookup": {"entity": "core.contact_infos", "label_column": "contact_infos.email_address", "value_column": "contact_infos.id"}, "filterable": true}, "order_fulfillment_status_id": {"name": "order_fulfillment_status_id", "type": "lookup", "width": 150, "header": "Fulfillment Status", "lookup": {"entity": "sales.order_fulfillment_statuses", "label_column": "order_fulfillment_statuses.name", "value_column": "order_fulfillment_statuses.id"}, "filterable": true}, "customer_delivery_address_id": {"name": "customer_delivery_address_id", "type": "lookup", "width": 200, "header": "Delivery Address", "lookup": {"entity": "geography.addresses", "label_column": "addresses.street", "value_column": "addresses.id"}, "filterable": true}, "fulfillment_status_description": {"name": "fulfillment_status_description", "type": "string", "width": 200, "header": "Status Description"}}}, "refresh_interval": 300}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.42707', '2026-03-19 15:16:53.42707', false);
INSERT INTO config.table_configs VALUES ('1947fecf-2f83-4acb-83b2-4d887db9c249', 'products_dashboard', 'products', '{"title": "Products List", "width": 12, "height": 8, "position_x": 0, "position_y": 0, "data_source": [{"type": "query", "schema": "products", "select": {"columns": [{"name": "id", "table_column": "products.id"}, {"name": "name", "table_column": "products.name"}, {"name": "sku", "table_column": "products.sku"}, {"name": "is_active", "table_column": "products.is_active"}]}, "source": "products"}], "permissions": {"roles": ["admin"], "actions": ["view"]}, "widget_type": "table", "refresh_mode": "polling", "visualization": "table", "visual_settings": {"columns": {"products.id": {"name": "products.id", "type": "uuid", "header": "ID", "hidden": true}, "products.sku": {"name": "products.sku", "type": "string", "width": 150, "header": "SKU", "editable": {"type": "text", "placeholder": "SKU-12345"}, "sortable": true, "filterable": true}, "products.name": {"name": "products.name", "type": "string", "width": 200, "header": "Product Name", "sortable": true, "filterable": true}, "products.is_active": {"name": "products.is_active", "type": "boolean", "width": 100, "header": "Is Active", "editable": {"type": "boolean"}, "sortable": true, "filterable": true}}, "pagination": {"enabled": true, "page_sizes": [10, 25, 50, 100], "default_page_size": 25}}, "refresh_interval": 300}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.43163', '2026-03-19 15:16:53.43163', false);
INSERT INTO config.table_configs VALUES ('94c1a8b4-9e97-411e-91c1-30c3c27dfc59', 'inventory_dashboard', 'inventory_items', '{"title": "Current Inventory with Products", "width": 12, "height": 8, "position_x": 0, "position_y": 0, "data_source": [{"rows": 50, "sort": [{"column": "quantity", "direction": "asc"}], "type": "query", "schema": "inventory", "select": {"columns": [{"name": "id", "table_column": "inventory_items.id"}, {"name": "quantity", "alias": "current_quantity", "table_column": "inventory_items.quantity"}, {"name": "reorder_point", "alias": "reorder_point", "table_column": "inventory_items.reorder_point"}, {"name": "maximum_stock", "alias": "maximum_stock", "table_column": "inventory_items.maximum_stock"}], "foreign_tables": [{"table": "products", "schema": "products", "columns": [{"name": "id", "alias": "product_id", "table_column": "products.id"}, {"name": "name", "alias": "product_name", "table_column": "products.name"}, {"name": "sku", "table_column": "products.sku"}], "join_type": "inner", "relationship_to": "products.id", "relationship_from": "inventory_items.product_id"}], "client_computed_columns": [{"name": "stock_status", "expression": "current_quantity <= reorder_point ? ''low'' : ''normal''"}, {"name": "stock_percentage", "expression": "(current_quantity / maximum_stock) * 100"}]}, "source": "inventory_items", "filters": [{"value": 0, "column": "quantity", "operator": "gt"}]}], "permissions": {"roles": ["admin", "inventory_manager"], "actions": ["view", "export", "adjust"]}, "widget_type": "table", "refresh_mode": "polling", "visualization": "table", "visual_settings": {"columns": {"product_id": {"name": "", "header": "", "hidden": true}, "product_name": {"link": {"url": "/products/products/{product_id}", "label_column": "product_name"}, "name": "product_name", "type": "string", "order": 10, "width": 250, "header": "Product", "sortable": true, "filterable": true}, "products.sku": {"name": "products.sku", "type": "string", "order": 50, "width": 120, "header": "SKU"}, "stock_status": {"name": "stock_status", "type": "computed", "align": "center", "order": 30, "width": 100, "header": "Status", "cell_template": "status"}, "maximum_stock": {"name": "maximum_stock", "type": "number", "width": 100, "header": "Maximum Stock", "hidden": true}, "reorder_point": {"name": "reorder_point", "type": "number", "width": 100, "header": "Reorder Point", "hidden": true}, "current_quantity": {"name": "current_quantity", "type": "number", "align": "right", "order": 20, "width": 120, "format": {"type": "number"}, "header": "Current Stock"}, "stock_percentage": {"name": "stock_percentage", "type": "computed", "align": "right", "order": 40, "width": 100, "format": {"type": "percent", "precision": 1}, "header": "Capacity"}, "inventory_items.id": {"name": "", "header": "", "hidden": true}}, "conditional_formatting": [{"icon": "alert-circle", "color": "#ff4444", "value": "low", "column": "stock_status", "condition": "eq", "background": "#ffebee"}, {"icon": "check-circle", "color": "#00C851", "value": "normal", "column": "stock_status", "condition": "eq", "background": "#e8f5e9"}]}, "refresh_interval": 300}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.434327', '2026-03-19 15:16:53.434327', false);
INSERT INTO config.table_configs VALUES ('b3696a06-7755-453f-948a-92792c233583', 'orders_table', 'orders', '{"title": "Orders Management", "width": 12, "height": 8, "position_x": 0, "position_y": 0, "data_source": [{"rows": 50, "sort": [{"column": "due_date", "direction": "desc"}], "type": "query", "schema": "sales", "select": {"columns": [{"name": "id", "table_column": "orders.id"}, {"name": "number", "alias": "order_number", "table_column": "orders.number"}, {"name": "due_date", "alias": "due_date", "table_column": "orders.due_date"}, {"name": "customer_id", "table_column": "orders.customer_id"}, {"name": "order_fulfillment_status_id", "table_column": "orders.order_fulfillment_status_id"}, {"name": "created_date", "table_column": "orders.created_date"}, {"name": "updated_date", "table_column": "orders.updated_date"}], "foreign_tables": [{"table": "customers", "schema": "sales", "columns": [{"name": "name", "alias": "customer_name", "table_column": "customers.name"}], "join_type": "left", "relationship_to": "customers.id", "relationship_from": "orders.customer_id"}, {"table": "order_fulfillment_statuses", "schema": "sales", "columns": [{"name": "name", "alias": "status_name", "table_column": "order_fulfillment_statuses.name"}, {"name": "description", "alias": "status_description", "table_column": "order_fulfillment_statuses.description"}], "join_type": "left", "relationship_to": "order_fulfillment_statuses.id", "relationship_from": "orders.order_fulfillment_status_id"}], "client_computed_columns": [{"name": "days_until_due", "expression": "daysUntil(due_date)"}, {"name": "is_overdue", "expression": "isOverdue(due_date) && status_name != ''Delivered''"}]}, "source": "orders"}], "permissions": {"roles": ["admin", "sales"], "actions": ["view", "edit", "export"]}, "widget_type": "table", "refresh_mode": "polling", "visualization": "table", "visual_settings": {"columns": {"due_date": {"name": "due_date", "type": "datetime", "width": 120, "format": {"type": "date", "format": "yyyy-MM-dd"}, "header": "Due Date", "sortable": true}, "orders.id": {"name": "orders.id", "type": "uuid", "header": "Order ID", "hidden": true}, "is_overdue": {"name": "is_overdue", "type": "boolean", "width": 80, "header": "Overdue"}, "status_name": {"name": "status_name", "type": "status", "width": 150, "header": "Status", "sortable": true, "filterable": true, "cell_template": "status"}, "order_number": {"link": {"url": "/sales/orders/{orders.id}", "label_column": "order_number"}, "name": "order_number", "type": "string", "width": 150, "header": "Order #", "sortable": true}, "customer_name": {"link": {"url": "/sales/customers/{orders.customer_id}", "label_column": "customer_name"}, "name": "customer_name", "type": "string", "width": 200, "header": "Customer", "sortable": true}, "days_until_due": {"name": "days_until_due", "type": "number", "align": "center", "width": 120, "format": {"type": "number"}, "header": "Days Until Due"}, "orders.customer_id": {"name": "orders.customer_id", "type": "uuid", "header": "Customer ID", "hidden": true}, "status_description": {"name": "status_description", "type": "string", "width": 200, "header": "Status Description"}, "orders.created_date": {"name": "orders.created_date", "type": "datetime", "width": 120, "format": {"type": "date", "format": "MM-dd-yyyy"}, "header": "Created Date"}, "orders.updated_date": {"name": "orders.updated_date", "type": "datetime", "width": 120, "format": {"type": "date", "format": "MM-dd-yyyy"}, "header": "Updated Date"}, "orders.order_fulfillment_status_id": {"name": "", "header": "", "hidden": true}}, "pagination": {"enabled": true, "page_sizes": [10, 25, 50, 100], "default_page_size": 25}, "conditional_formatting": [{"color": "red", "value": 0, "column": "days_until_due", "condition": "lt"}, {"color": "yellow", "value": 7, "column": "days_until_due", "condition": "lte"}, {"color": "red", "value": true, "column": "is_overdue", "condition": "eq"}]}, "refresh_interval": 300}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.437322', '2026-03-19 15:16:53.437322', false);
INSERT INTO config.table_configs VALUES ('aa8b6e2b-6d58-4c57-ac91-59eb02cab636', 'suppliers_table', 'suppliers', '{"title": "Suppliers Management", "width": 12, "height": 8, "position_x": 0, "position_y": 0, "data_source": [{"rows": 50, "sort": [{"column": "suppliers.rating", "direction": "desc"}, {"column": "suppliers.name", "direction": "asc"}], "type": "query", "schema": "procurement", "select": {"columns": [{"name": "id", "alias": "suppliers_id", "table_column": "suppliers.id"}, {"name": "name", "alias": "suppliers_name", "table_column": "suppliers.name"}, {"name": "lead_time_days", "alias": "suppliers_lead_time_days", "table_column": "suppliers.lead_time_days"}, {"name": "rating", "alias": "suppliers_rating", "table_column": "suppliers.rating"}, {"name": "is_active", "alias": "suppliers_is_active", "table_column": "suppliers.is_active"}, {"name": "contact_infos_id", "alias": "suppliers_contact_infos_id", "table_column": "suppliers.contact_infos_id"}, {"name": "created_date", "alias": "suppliers_created_date", "table_column": "suppliers.created_date"}, {"name": "updated_date", "alias": "suppliers_updated_date", "table_column": "suppliers.updated_date"}], "foreign_tables": [{"table": "contact_infos", "schema": "core", "columns": [{"name": "primary_phone_number", "alias": "primary_phone_number", "table_column": "contact_infos.primary_phone_number"}, {"name": "secondary_phone_number", "alias": "secondary_phone_number", "table_column": "contact_infos.secondary_phone_number"}, {"name": "email_address", "alias": "email_address", "table_column": "contact_infos.email_address"}], "join_type": "left", "relationship_to": "contact_infos.id", "relationship_from": "suppliers.contact_infos_id"}, {"table": "payment_terms", "schema": "core", "columns": [{"name": "name", "alias": "payment_terms", "table_column": "payment_terms.name"}], "join_type": "left", "relationship_to": "payment_terms.id", "relationship_from": "suppliers.payment_term_id"}], "client_computed_columns": [{"name": "rating_stars", "expression": "round(suppliers_rating * 2) / 2"}, {"name": "performance_level", "expression": "suppliers_rating >= 4.5 ? ''excellent'' : suppliers_rating >= 3.5 ? ''good'' : suppliers_rating >= 2.5 ? ''fair'' : ''poor''"}]}, "source": "suppliers", "filters": [{"value": true, "column": "suppliers.is_active", "operator": "eq"}]}], "permissions": {"roles": ["admin", "procurement", "inventory_manager"], "actions": ["view", "edit", "export"]}, "widget_type": "table", "refresh_mode": "polling", "visualization": "table", "visual_settings": {"columns": {"rating_stars": {"name": "rating_stars", "type": "computed", "width": 100, "header": "Rating Stars"}, "suppliers_id": {"name": "suppliers_id", "type": "uuid", "header": "Supplier ID", "hidden": true}, "email_address": {"name": "email_address", "type": "string", "width": 200, "header": "Email"}, "payment_terms": {"name": "payment_terms", "type": "string", "width": 150, "header": "Payment Terms", "sortable": true, "filterable": true}, "suppliers_name": {"link": {"url": "/procurement/suppliers/{suppliers_id}", "label_column": "suppliers_name"}, "name": "suppliers_name", "type": "string", "width": 200, "header": "Supplier Name", "sortable": true, "filterable": true}, "suppliers_rating": {"name": "suppliers_rating", "type": "number", "align": "center", "width": 100, "format": {"type": "number", "precision": 2}, "header": "Rating", "sortable": true}, "performance_level": {"name": "performance_level", "type": "computed", "align": "center", "width": 120, "header": "Performance", "cell_template": "badge"}, "suppliers_is_active": {"name": "suppliers_is_active", "type": "boolean", "align": "center", "width": 80, "format": {"type": "boolean"}, "header": "Active", "editable": {"type": "boolean"}}, "primary_phone_number": {"name": "primary_phone_number", "type": "string", "width": 150, "header": "Primary Phone"}, "secondary_phone_number": {"name": "secondary_phone_number", "type": "string", "width": 150, "header": "Secondary Phone"}, "suppliers_created_date": {"name": "suppliers_created_date", "type": "datetime", "width": 120, "format": {"type": "date", "format": "MM-dd-yyyy"}, "header": "Created Date"}, "suppliers_updated_date": {"name": "suppliers_updated_date", "type": "datetime", "width": 120, "format": {"type": "date", "format": "MM-dd-yyyy"}, "header": "Updated Date"}, "suppliers_lead_time_days": {"name": "suppliers_lead_time_days", "type": "number", "align": "center", "width": 130, "format": {"type": "number"}, "header": "Lead Time (days)", "sortable": true}, "suppliers_contact_infos_id": {"name": "", "header": "", "hidden": true}}, "pagination": {"enabled": true, "page_sizes": [10, 25, 50, 100], "default_page_size": 25}, "conditional_formatting": [{"icon": "star", "color": "#1b5e20", "value": "excellent", "column": "performance_level", "condition": "eq", "background": "#c8e6c9"}, {"icon": "check-circle", "color": "#2e7d32", "value": "good", "column": "performance_level", "condition": "eq", "background": "#e8f5e9"}, {"icon": "alert-circle", "color": "#f57c00", "value": "fair", "column": "performance_level", "condition": "eq", "background": "#fff3e0"}, {"icon": "x-circle", "color": "#c62828", "value": "poor", "column": "performance_level", "condition": "eq", "background": "#ffebee"}, {"color": "#757575", "value": false, "column": "is_active", "condition": "eq", "background": "#f5f5f5"}]}, "refresh_interval": 300}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.440834', '2026-03-19 15:16:53.440834', false);
INSERT INTO config.table_configs VALUES ('c94df673-e97d-4999-9bf8-8f916df69375', 'categories_table', 'product_categories', '{"title": "Product Categories", "width": 12, "height": 8, "position_x": 0, "position_y": 0, "data_source": [{"rows": 50, "sort": [{"column": "name", "direction": "asc"}], "type": "query", "schema": "products", "select": {"columns": [{"name": "id", "table_column": "product_categories.id"}, {"name": "name", "table_column": "product_categories.name"}, {"name": "description", "table_column": "product_categories.description"}, {"name": "created_date", "table_column": "product_categories.created_date"}, {"name": "updated_date", "table_column": "product_categories.updated_date"}]}, "source": "product_categories"}], "permissions": {"roles": ["admin", "product_manager"], "actions": ["view", "edit", "delete", "export"]}, "widget_type": "table", "refresh_mode": "polling", "visualization": "table", "visual_settings": {"columns": {"product_categories.id": {"name": "product_categories.id", "type": "uuid", "header": "Category ID", "hidden": true}, "product_categories.name": {"link": {"url": "/products/categories/{product_categories.id}", "label_column": "product_categories.name"}, "name": "product_categories.name", "type": "string", "width": 250, "header": "Category Name", "editable": {"type": "text", "placeholder": "Category name"}, "sortable": true, "filterable": true}, "product_categories.description": {"name": "product_categories.description", "type": "string", "width": 400, "header": "Description", "editable": {"type": "textarea", "placeholder": "Category description"}, "filterable": true}, "product_categories.created_date": {"name": "product_categories.created_date", "type": "datetime", "width": 150, "format": {"type": "datetime", "format": "yyyy-MM-dd HH:mm"}, "header": "Created", "sortable": true}, "product_categories.updated_date": {"name": "product_categories.updated_date", "type": "datetime", "width": 150, "format": {"type": "datetime", "format": "