INSERT INTO config.table_configs VALUES ('78ca37b1-3081-4eac-a35a-29c02c6eac05', 'order_line_items_table', 'order_line_items', '{"title": "Order Line Items", "width": 12, "height": 8, "position_x": 0, "position_y": 0, "data_source": [{"rows": 50, "sort": [{"column": "order_date", "direction": "desc"}, {"column": "id", "direction": "asc"}], "type": "query", "schema": "sales", "select": {"columns": [{"name": "id", "table_column": "order_line_items.id"}, {"name": "order_id", "table_column": "order_line_items.order_id"}, {"name": "product_id", "table_column": "order_line_items.product_id"}, {"name": "quantity", "alias": "quantity", "table_column": "order_line_items.quantity"}, {"name": "discount", "alias": "discount", "table_column": "order_line_items.discount"}, {"name": "line_item_fulfillment_statuses_id", "table_column": "order_line_items.line_item_fulfillment_statuses_id"}, {"name": "created_by", "table_column": "order_line_items.created_by"}, {"name": "created_date", "table_column": "order_line_items.created_date"}, {"name": "updated_by", "table_column": "order_line_items.updated_by"}, {"name": "updated_date", "table_column": "order_line_items.updated_date"}], "foreign_tables": [{"table": "orders", "schema": "sales", "columns": [{"name": "number", "alias": "order_number", "table_column": "orders.number"}, {"name": "order_date", "alias": "order_date", "table_column": "orders.order_date"}, {"name": "customer_id", "alias": "order_customer_id", "table_column": "orders.customer_id"}], "join_type": "left", "foreign_tables": [{"table": "customers", "schema": "sales", "columns": [{"name": "name", "alias": "customer_name", "table_column": "customers.name"}], "join_type": "left", "relationship_to": "customers.id", "relationship_from": "orders.customer_id"}], "relationship_to": "orders.id", "relationship_from": "order_line_items.order_id"}, {"table": "products", "schema": "products", "columns": [{"name": "name", "alias": "product_name", "table_column": "products.name"}, {"nam