INSERT INTO config.table_configs VALUES ('75fa5671-9cf4-4201-8e64-1ba67629226b', 'seed_kpi_total_revenue', 'KPI showing total revenue', '{"title": "Total Revenue", "width": 0, "height": 0, "position_x": 0, "position_y": 0, "data_source": [{"type": "query", "schema": "sales", "select": {"columns": null, "foreign_tables": [{"table": "products", "schema": "products", "columns": null, "join_type": "inner", "foreign_tables": [{"table": "product_costs", "schema": "products", "columns": null, "join_type": "inner", "relationship_to": "product_costs.product_id", "relationship_from": "products.id"}], "relationship_to": "products.id", "relationship_from": "order_line_items.product_id"}]}, "source": "order_line_items", "metrics": [{"name": "total_revenue", "function": "sum", "expression": {"columns": ["order_line_items.quantity", "product_costs.selling_price"], "operator": "multiply"}}]}], "permissions": {"roles": null, "actions": null}, "widget_type": "chart", "refresh_mode": "", "visualization": "kpi", "visual_settings": {"columns": {"_chart": {"name": "", "header": "", "cell_template": "{\"chartType\":\"kpi\",\"valueColumns\":[\"total_revenue\"],\"kpi\":{\"label\":\"Total Revenue\",\"format\":\"currency\"}}"}}}, "refresh_interval": 0}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.516123', '2026-03-19 15:16:53.516123', false);
