INSERT INTO config.table_configs VALUES ('8bd7cd3e-7132-494f-80b3-78fac980ec70', 'seed_gantt_project', 'Gantt chart showing purchase order timeline', '{"title": "Purchase Order Timeline", "width": 0, "height": 0, "position_x": 0, "position_y": 0, "data_source": [{"rows": 20, "sort": [{"column": "order_date", "direction": "asc"}], "type": "query", "schema": "procurement", "select": {"columns": [{"name": "id", "alias": "id"}, {"name": "order_number", "alias": "name"}, {"name": "order_date", "alias": "start_date"}, {"name": "expected_delivery_date", "alias": "end_date"}]}, "source": "purchase_orders"}], "permissions": {"roles": null, "actions": null}, "widget_type": "chart", "refresh_mode": "", "visualization": "gantt", "visual_settings": {"columns": {"_chart": {"name": "", "header": "", "cell_template": "{\"chartType\":\"gantt\",\"nameColumn\":\"name\",\"startColumn\":\"start_date\",\"endColumn\":\"end_date\"}"}}}, "refresh_interval": 0}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.561556', '2026-03-19 15:16:53.561556', false);
INSERT INTO config.table_configs VALUES ('6f44562b-b955-42aa-bc1d-f4b30a05f45c', 'seed_pie_revenue_category', 'Pie chart showing revenue by category', '{"title": "Revenue by Category", "width": 0, "height": 0, "position_x": 0, "position_y": 0, "data_source": [{"type": "query", "schema": "sales", "select": {"columns": null, "foreign_tables": [{"table": "products", "schema": "products", "columns": null, "join_type": "inner", "foreign_tables": [{"table": "product_categories", "schema": "products", "columns": null, "join_type": "inner", "relationship_to": "product_categories.id", "relationship_from": "products.category_id"}, {"table": "product_costs", "schema": "products", "columns": null, "join_type": "inner", "relationship_to": "product_costs.product_id", "relationship_from": "products.id"}], "relationship_to": "products.id", "relationship_from": "order_line_items.product_id"}]}, "source": "order_line_items", "metrics": [{"name": "revenue", "function": "sum", "expression": {"columns": ["order_line_items.quantity", "product_costs.selling_price"], "operator": "multiply"}}], "group_by": [{"alias": "category", "column": "product_categories.name"}]}], "permissions": {"roles": null, "actions": null}, "widget_type": "chart", "refresh_mode": "", "visualization": "pie", "visual_settings": {"columns": {"_chart": {"name": "", "header": "", "cell_template": "{\"chartType\":\"pie\",\"categoryColumn\":\"category\",\"valueColumns\":[\"revenue\"]}"}}}, "refresh_interval": 0}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.545517', '2026-03-19 15:16:53.545517', false);
INSERT INTO config.table_configs VALUES ('d2dc1f2e-f95d-440a-82b6-3fffaacd0554', 'seed_combo_revenue_orders', 'Combo chart comparing revenue vs order count', '{"title": "Revenue vs Order Count", "width": 0, "height": 0, "position_x": 0, "position_y": 0, "data_source": [{"sort": [{"column": "month", "direction": "asc"}], "type": "query", "schema": "sales", "select": {"columns": null, "foreign_tables": [{"table": "orders", "schema": "sales", "columns": null, "join_type": "inner", "relationship_to": "orders.id", "relationship_from": "order_line_items.order_id"}, {"table": "products", "schema": "products", "columns": null, "join_type": "inner", "foreign_tables": [{"table": "product_costs", "schema": "products", "columns": null, "join_type": "inner", "relationship_to": "product_costs.product_id", "relationship_from": "products.id"}], "relationship_to": "products.id", "relationship_from": "order_line_items.product_id"}]}, "source": "order_line_items", "metrics": [{"name": "revenue", "function": "sum", "expression": {"columns": ["order_line_items.quantity", "product_costs.selling_price"], "operator": "multiply"}}, {"name": "order_count", "column": "orders.id", "function": "count_distinct"}], "group_by": [{"alias": "month", "column": "orders.created_date", "interval": "month"}]}], "permissions": {"roles": null, "actions": null}, "widget_type": "chart", "refresh_mode": "", "visualization": "combo", "visual_settings": {"columns": {"_chart": {"name": "", "header": "", "cell_template": "{\"chartType\":\"combo\",\"categoryColumn\":\"month\",\"valueColumns\":[\"revenue\",\"order_count\"],\"xAxis\":{\"title\":\"Month\",\"type\":\"time\"},\"yAxis\":{\"title\":\"Revenue ($)\",\"type\":\"value\",\"format\":\"currency\"},\"y2Axis\":{\"title\":\"Order Count\",\"type\":\"value\"},\"seriesConfig\":[{\"column\":\"revenue\",\"type\":\"bar\",\"label\":\"Revenue\"},{\"column\":\"order_count\",\"type\":\"line\",\"yAxisIndex\":1,\"label\":\"Orders\"}]}"}}}, "refresh_interval": 0}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.548146', '2026-03-19 15:16:53.548147', false);
INSERT INTO config.table_configs VALUES ('efe7e335-9aa6-4865-b2ba-1f6b684f7c6e', 'seed_waterfall_profit', 'Waterfall chart showing profit breakdown', '{"title": "Profit Breakdown", "width": 0, "height": 0, "position_x": 0, "position_y": 0, "data_source": [{"type": "query", "schema": "sales", "select": {"columns": null, "foreign_tables": [{"table": "products", "schema": "products", "columns": null, "join_type": "inner", "foreign_tables": [{"table": "product_costs", "schema": "products", "columns": null, "join_type": "inner", "relationship_to": "product_costs.product_id", "relationship_from": "products.id"}], "relationship_to": "products.id", "relationship_from": "order_line_items.product_id"}]}, "source": "order_line_items", "metrics": [{"name": "amount", "function": "sum", "expression": {"columns": ["order_line_items.quantity", "product_costs.selling_price"], "operator": "multiply"}}]}], "permissions": {"roles": null, "actions": null}, "widget_type": "chart", "refresh_mode": "", "visualization": "waterfall", "visual_settings": {"columns": {"_chart": {"name": "", "header": "", "cell_template": "{\"chartType\":\"waterfall\",\"categoryColumn\":\"category\",\"valueColumns\":[\"amount\"]}"}}}, "refresh_interval": 0}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.550872', '2026-03-19 15:16:53.550872', false);
INSERT INTO config.table_configs VALUES ('d56ed628-87dd-43dc-8539-95197968336f', 'seed_funnel_pipeline', 'Funnel chart showing sales pipeline stages', '{"title": "Sales Pipeline", "width": 0, "height": 0, "position_x": 0, "position_y": 0, "data_source": [{"type": "query", "schema": "sales", "select": {"columns": null, "foreign_tables": [{"table": "order_fulfillment_statuses", "schema": "sales", "columns": null, "join_type": "inner", "relationship_to": "order_fulfillment_statuses.id", "relationship_from": "orders.order_fulfillment_status_id"}]}, "source": "orders", "metrics": [{"name": "count", "column": "orders.id", "function": "count"}], "group_by": [{"alias": "status", "column": "order_fulfillment_statuses.name"}]}], "permissions": {"roles": null, "actions": null}, "widget_type": "chart", "refresh_mode": "", "visualization": "funnel", "visual_settings": {"columns": {"_chart": {"name": "", "header": "", "cell_template": "{\"chartType\":\"funnel\",\"categoryColumn\":\"status\",\"valueColumns\":[\"count\"]}"}}}, "refresh_interval": 0}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.553526', '2026-03-19 15:16:53.553526', false);
INSERT INTO config.table_configs VALUES ('ea2bfa2a-27b7-4352-9086-03448283b82d', 'seed_heatmap_sales_time', 'Heatmap showing orders by day and hour', '{"title": "Orders by Day and Hour", "width": 0, "height": 0, "position_x": 0, "position_y": 0, "data_source": [{"type": "query", "schema": "sales", "select": {"columns": null}, "source": "orders", "metrics": [{"name": "count", "column": "orders.id", "function": "count"}], "group_by": [{"alias": "day", "column": "EXTRACT(DOW FROM orders.created_date)", "expression": true}, {"alias": "hour", "column": "EXTRACT(HOUR FROM orders.created_date)", "expression": true}]}], "permissions": {"roles": null, "actions": null}, "widget_type": "chart", "refresh_mode": "", "visualization": "heatmap", "visual_settings": {"columns": {"_chart": {"name": "", "header": "", "cell_template": "{\"chartType\":\"heatmap\",\"valueColumns\":[\"count\"],\"xCategoryColumn\":\"hour\",\"yCategoryColumn\":\"day\"}"}}}, "refresh_interval": 0}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.556054', '2026-03-19 15:16:53.556054', false);
INSERT INTO config.table_configs VALUES ('9b54798d-6485-4b1e-a4d3-8c271fcde95a', 'seed_treemap_revenue', 'Treemap showing revenue breakdown by product', '{"title": "Revenue Breakdown by Product", "width": 0, "height": 0, "position_x": 0, "position_y": 0, "data_source": [{"rows": 20, "type": "query", "schema": "sales", "select": {"columns": null, "foreign_tables": [{"table": "products", "schema": "products", "columns": null, "join_type": "inner", "foreign_tables": [{"table": "product_costs", "schema": "products", "columns": null, "join_type": "inner", "relationship_to": "product_costs.product_id", "relationship_from": "products.id"}], "relationship_to": "products.id", "relationship_from": "order_line_items.product_id"}]}, "source": "order_line_items", "metrics": [{"name": "revenue", "function": "sum", "expression": {"columns": ["order_line_items.quantity", "product_costs.selling_price"], "operator": "multiply"}}], "group_by": [{"alias": "product", "column": "products.name"}]}], "permissions": {"roles": null, "actions": null}, "widget_type": "chart", "refresh_mode": "", "visualization": "treemap", "visual_settings": {"columns": {"_chart": {"name": "", "header": "", "cell_template": "{\"chartType\":\"treemap\",\"categoryColumn\":\"product\",\"valueColumns\":[\"revenue\"]}"}}}, "refresh_interval": 0}', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', 'b4f7bc0c-9d8e-4834-a236-1204ae3d7254', '2026-03-19 15:16:53.558967', '2026-03-19 15:16:53.558967', false);
